import { MapContainer, TileLayer, Marker, Popup, useMap } from "react-leaflet";
import L from "leaflet";
import { useNavigate } from "react-router-dom";

// Leaflet icon fix
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: require("leaflet/dist/images/marker-icon-2x.png"),
  iconUrl:       require("leaflet/dist/images/marker-icon.png"),
  shadowUrl:     require("leaflet/dist/images/marker-shadow.png"),
});

// Category icon colors
const CAT_COLORS = {
  hairsalon: "#3B82F6",
  beauty:    "#EC4899",
  billiard:  "#10B981",
  cafe:      "#F59E0B",
  fitness:   "#8B5CF6",
  other:     "#6B7280",
};

const CAT_ICONS = { hairsalon:"✂", beauty:"💄", billiard:"🎱", cafe:"☕", fitness:"💪", other:"📍" };

function createIcon(cat) {
  const color = CAT_COLORS[cat] || "#6B7280";
  const icon  = CAT_ICONS[cat] || "📍";
  return L.divIcon({
    html: `<div style="
      width:36px;height:36px;border-radius:50% 50% 50% 0;
      background:${color};transform:rotate(-45deg);
      display:flex;align-items:center;justify-content:center;
      box-shadow:0 2px 8px rgba(0,0,0,0.4);
      border:2px solid rgba(255,255,255,0.3);
    "><span style="transform:rotate(45deg);font-size:14px">${icon}</span></div>`,
    className: "",
    iconSize: [36, 36],
    iconAnchor: [18, 36],
    popupAnchor: [0, -38],
  });
}

// User location marker
const userIcon = L.divIcon({
  html: `<div style="
    width:16px;height:16px;border-radius:50%;
    background:#2563EB;border:3px solid #fff;
    box-shadow:0 0 0 4px rgba(37,99,235,0.3);
  "></div>`,
  className: "",
  iconSize: [16, 16],
  iconAnchor: [8, 8],
});

function FlyTo({ center }) {
  const map = useMap();
  if (center) map.flyTo(center, 14, { duration: 1.2 });
  return null;
}

export default function MapView({ businesses, userPos, center }) {
  const nav = useNavigate();

  return (
    <MapContainer
      center={center || [47.9077, 106.8832]}
      zoom={13}
      style={{ width:"100%", height:"100%" }}
      zoomControl={false}
    >
      <TileLayer
        attribution='© <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
        url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
      />

      {center && <FlyTo center={center} />}

      {/* User location */}
      {userPos && <Marker position={userPos} icon={userIcon} />}

      {/* Business markers */}
      {businesses.map(b => (
        <Marker key={b._id} position={[b.location.lat, b.location.lng]} icon={createIcon(b.category)}>
          <Popup>
            <div style={{ minWidth:200, fontFamily:"Inter,sans-serif" }}>
              <div style={{ fontWeight:700, fontSize:15, marginBottom:4 }}>{b.name}</div>
              <div style={{ fontSize:12, color:"#8B949E", marginBottom:8 }}>{b.address}</div>
              {b.distance != null &&
                <div style={{ fontSize:12, color:"#60A5FA", marginBottom:8 }}>📍 {b.distance} км</div>}
              <div style={{ display:"flex", alignItems:"center", gap:4, marginBottom:10 }}>
                <span style={{ color:"#F59E0B" }}>⭐</span>
                <span style={{ fontSize:13, fontWeight:600 }}>{b.rating}</span>
                <span style={{ fontSize:12, color:"#8B949E" }}>({b.reviewCount} үнэлгээ)</span>
              </div>
              <button onClick={() => nav(`/business/${b._id}`)} style={{
                width:"100%", padding:"8px 0",
                background:"#2563EB", color:"#fff",
                border:"none", borderRadius:6, cursor:"pointer",
                fontSize:13, fontWeight:500,
              }}>Дэлгэрэнгүй →</button>
            </div>
          </Popup>
        </Marker>
      ))}
    </MapContainer>
  );
}
